import{_ as i,o as a,c as e,ak as n}from"./chunks/framework.Bj6Oe1e0.js";const c=JSON.parse('{"title":"Unitree-MuJoCo 仿真环境搭建","description":"","frontmatter":{},"headers":[],"relativePath":"宇树 G1/Unitree-MuJoCo 仿真环境.md","filePath":"宇树 G1/Unitree-MuJoCo 仿真环境.md"}'),l={name:"宇树 G1/Unitree-MuJoCo 仿真环境.md"};function t(h,s,p,k,r,d){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="unitree-mujoco-仿真环境搭建" tabindex="-1">Unitree-MuJoCo 仿真环境搭建 <a class="header-anchor" href="#unitree-mujoco-仿真环境搭建" aria-label="Permalink to “Unitree-MuJoCo 仿真环境搭建”">​</a></h1><p>Unitree 为在虚拟环境下调试机器人，提供了一套基于 Google DeepMind MuJoCo 的仿真环境。</p><blockquote><p>MuJoCo 是一套开源的物理引擎，提供一系列物理效果。</p></blockquote><p>Unitree-MuJoCo 是一个基于 Unitree SDK 和 MuJoCo 开发的模拟器，其可以集成 Unitree SDK 2、Unitree ROS 2 开发的控制程序到模拟器中，实现无缝过渡。</p><blockquote><p>本文默认使用 C++ / ROS 2 for C++ 搭建。官方教程为 Ubuntu 20.04/22.04 + ROS Foxy，笔者实测 Ubuntu 24.04 + ROS Jazzy 同样可行。</p></blockquote><h2 id="基础环境搭建" tabindex="-1">基础环境搭建 <a class="header-anchor" href="#基础环境搭建" aria-label="Permalink to “基础环境搭建”">​</a></h2><p>首先需要安装 Unitree SDK。</p><h3 id="依赖关系" tabindex="-1">依赖关系 <a class="header-anchor" href="#依赖关系" aria-label="Permalink to “依赖关系”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libyaml-cpp-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libspdlog-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libboost-all-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libglfw3-dev</span></span></code></pre></div><h3 id="unitree-sdk-2" tabindex="-1">Unitree SDK 2 <a class="header-anchor" href="#unitree-sdk-2" aria-label="Permalink to “Unitree SDK 2”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/unitreerobotics/unitree_sdk2.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unitree_sdk2/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -DCMAKE_INSTALL_PREFIX=/opt/unitree_robotics</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h3 id="mujoco" tabindex="-1">MuJoCO <a class="header-anchor" href="#mujoco" aria-label="Permalink to “MuJoCO”">​</a></h3><p>在 <a href="https://github.com/google-deepmind/mujoco/releases" target="_blank" rel="noreferrer">MuJoCo 官方下载页面</a> 下载最新的 Release，解压到 <code>~/.mujoco</code> 目录。然后将其软链接到 <code>unitree_mujoco/simulate/mujoco</code> 中：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unitree_mujoco/simulate/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.mujoco/mujoco-3.3.6</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mujoco</span></span></code></pre></div><p>然后进行编译：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unitree_mujoco/simulate</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j4</span></span></code></pre></div><p>此时会出现报错，提示缺少 <code>uint8_t</code> 等基础类型。这是因为在 <code>unitree_mujoco/simulate/src</code> 中的一个文件缺少头文件的引用。</p><p>在 <code>unitree_mujoco/simulate/src/joystick/jstest.cc</code> 中，添加头文件：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;cstdint&gt;</span></span></code></pre></div><p>即可解决问题。</p><h2 id="运行仿真环境" tabindex="-1">运行仿真环境 <a class="header-anchor" href="#运行仿真环境" aria-label="Permalink to “运行仿真环境”">​</a></h2><p>在 <code>unitree_mujoco/simulate/build</code> 目录下运行：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./unitree_mujoco</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> g1</span></span></code></pre></div><p>即可打开 MuJoCo 仿真器。可能会遇到以下报错：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">unitree_mujoco:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./src/core/ddsc/src/dds_write.c:318:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dds_writecdr_impl_common:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Assertion</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> \`(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wr-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&gt;m_iox_pub == NULL) == (d-&gt;a.iox_chunk == NULL)&#39; failed.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">unitree_mujoco： ./src/core/ddsc/src/dds_write.c：318： dds_writecdr_impl_common： 断言 &#39;（wr-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">m_iox_pub == NULL） == （d-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">a.iox_chunk == NULL）&#39; 失败。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">已中止 (核心已转储)</span></span></code></pre></div><p>这是由于 ROS2 和 CycloneDDS 环境冲突。可以通过清理在运行环境中的相关变量解决：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Clear ROS2 environment</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ROS_DISTRO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AMENT_PREFIX_PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CMAKE_PREFIX_PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LD_LIBRARY_PATH</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Minimal paths</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LD_LIBRARY_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/usr/local/lib:/usr/lib/x86_64-linux-gnu</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Disable Iceoryx in CycloneDDS</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CYCLONEDDS_URI</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&lt;CycloneDDS&gt;&lt;Domain&gt;&lt;Iceoryx&gt;&lt;Enable&gt;false&lt;/Enable&gt;&lt;/Iceoryx&gt;&lt;/Domain&gt;&lt;/CycloneDDS&gt;&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unitree_mujoco/simulate/build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./unitree_mujoco</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -go2</span></span></code></pre></div><p>即可运行起仿真环境。</p><h2 id="运行示例" tabindex="-1">运行示例 <a class="header-anchor" href="#运行示例" aria-label="Permalink to “运行示例”">​</a></h2><p>Unitree_MuJoCo 提供了一系列 examples 用于测试。进入 <code>unitree_mujoco/examples/cpp</code>，运行以下命令编译启动：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j4</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./stand_go2</span></span></code></pre></div><p>即可启动。可以观察到，在 MuJoCo 仿真环境中，机器人缓慢站立。</p><blockquote><p>在此之前也有可能需要清理 ROS 环境。Unitree-MuJoCo 仅给出了 Go2 的例程，G1 需要进行更改。</p></blockquote>`,33)])])}const g=i(l,[["render",t]]);export{c as __pageData,g as default};
